class Solution {
    public int findMaxK(int[] nums) {
        int maxK = -1;
        for (int num : nums) {
            if (num < 0 && contains(nums, -num)) {
                maxK = Math.max(maxK, -num);
            }
        }
        return maxK;
    }

    private boolean contains(int[] nums, int target) {
        for (int num : nums) {
            if (num == target) {
                return true;
            }
        }
        return false;
    }
}
